import{_ as o,c as t,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Add Account: OAuth & Refresh Token | Antigravity-Manager","description":"Learn two ways to add accounts to Antigravity Tools: one-click OAuth authorization and manual Refresh Token addition. Handle callback failures, verify account pool, and bulk import tokens.","frontmatter":{"title":"Add Account: OAuth & Refresh Token | Antigravity-Manager","sidebarTitle":"Add Account","subtitle":"Add Account: OAuth & Refresh Token","description":"Learn two ways to add accounts to Antigravity Tools: one-click OAuth authorization and manual Refresh Token addition. Handle callback failures, verify account pool, and bulk import tokens.","tags":["Account Management","OAuth","refresh_token","Google","Best Practices"],"prerequisite":["start-getting-started"],"duration":15,"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),n={name:"lbjlaq/Antigravity-Manager/start/add-account/index.md"};function c(l,e,i,s,d,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="add-account-oauth-refresh-token-dual-channel-best-practices" tabindex="-1">Add Account: OAuth/Refresh Token Dual-Channel &amp; Best Practices <a class="header-anchor" href="#add-account-oauth-refresh-token-dual-channel-best-practices" aria-label="Permalink to &quot;Add Account: OAuth/Refresh Token Dual-Channel &amp; Best Practices&quot;">​</a></h1><p>In Antigravity Tools, &quot;adding an account&quot; means writing a Google account&#39;s <code>refresh_token</code> into the local account pool, allowing subsequent reverse proxy requests to rotate through them. You can use OAuth one-click authorization, or directly paste <code>refresh_token</code> for manual addition.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Add Google accounts to Antigravity Tools account pool using OAuth or Refresh Token</li><li>Copy/manually open authorization links and automatically/manual complete adding after successful callback</li><li>Know how to handle issues like failing to get <code>refresh_token</code> or callback failing to connect to <code>localhost</code></li></ul><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><ul><li>Clicked &quot;OAuth Authorization&quot; but it keeps spinning, or browser shows <code>localhost refused to connect</code></li><li>Authorization succeeded but shows &quot;Refresh Token not obtained&quot;</li><li>You only have <code>refresh_token</code> and don&#39;t know how to batch import at once</li></ul><h2 id="when-to-use-this-method" tabindex="-1">When to Use This Method <a class="header-anchor" href="#when-to-use-this-method" aria-label="Permalink to &quot;When to Use This Method&quot;">​</a></h2><ul><li>You want the most stable way to add accounts (prioritize OAuth)</li><li>You care more about portability/backup (Refresh Token is better suited as &quot;account pool asset&quot;)</li><li>You need to add many accounts and want to batch import <code>refresh_token</code> (supports extraction from text/JSON)</li></ul><h2 id="🎒-preparation" tabindex="-1">🎒 Preparation <a class="header-anchor" href="#🎒-preparation" aria-label="Permalink to &quot;🎒 Preparation&quot;">​</a></h2><ul><li>You have installed and can open Antigravity Tools desktop app</li><li>You know where to enter: navigate to <code>Accounts</code> page from left sidebar (routing in <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">Two key terms in this lesson</p><p><strong>OAuth</strong>: A &quot;jump to browser to login and authorize&quot; flow. Antigravity Tools will temporarily start a local callback address (<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>, automatically selecting based on system IPv4/IPv6 listening status), wait for the browser to return with <code>code</code>, then exchange for token. (Implementation in <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>)</p><p><strong>refresh_token</strong>: A &quot;credential that can be used to refresh access_token for a long time&quot;. When adding an account in this project, it&#39;s used to first exchange for access_token, then fetch real email from Google, and ignore the email you input in frontend. (Implementation in <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>)</p></div><h2 id="core-approach" tabindex="-1">Core Approach <a class="header-anchor" href="#core-approach" aria-label="Permalink to &quot;Core Approach&quot;">​</a></h2><p>Antigravity Tools&#39; &quot;add account&quot; feature ultimately aims to get an available <code>refresh_token</code> and write account information to the local account pool.</p><ul><li><strong>OAuth Channel</strong>: App helps you generate authorization link and listen for local callback; after authorization completes, it automatically exchanges token and saves account (see <code>prepare_oauth_url</code>, <code>start_oauth_login</code>, <code>complete_oauth_login</code>)</li><li><strong>Refresh Token Channel</strong>: You directly paste <code>refresh_token</code>, app uses it to refresh access_token, fetches real email from Google, and saves to disk (see <code>add_account</code>)</li></ul><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-open-add-account-dialog" tabindex="-1">Step 1: Open &quot;Add Account&quot; Dialog <a class="header-anchor" href="#step-1-open-add-account-dialog" aria-label="Permalink to &quot;Step 1: Open &quot;Add Account&quot; Dialog&quot;">​</a></h3><p><strong>Why</strong> All add entry points are unified in the <code>Accounts</code> page.</p><p>Action: Navigate to <code>Accounts</code> page, click the <strong>Add Account</strong> button on the right (component: <code>AddAccountDialog</code>).</p><p><strong>You should see</strong>: A dialog with 3 tabs pops up: <code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code> (see <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code>).</p><h3 id="step-2-prioritize-oauth-one-click-authorization-recommended" tabindex="-1">Step 2: Prioritize OAuth One-Click Authorization (Recommended) <a class="header-anchor" href="#step-2-prioritize-oauth-one-click-authorization-recommended" aria-label="Permalink to &quot;Step 2: Prioritize OAuth One-Click Authorization (Recommended)&quot;">​</a></h3><p><strong>Why</strong> This is the product&#39;s default recommended path: let the app generate authorization link, automatically open browser, and automatically complete saving after callback returns.</p><ol><li>Switch to <code>OAuth</code> tab.</li><li>First copy authorization link: after dialog opens, it automatically calls <code>prepare_oauth_url</code> to pre-generate URL (frontend call in <code>AddAccountDialog.tsx:111-125</code>; backend generation and listening in <code>oauth_server.rs</code>).</li><li>Click <strong>Start OAuth</strong> (corresponds to frontend <code>startOAuthLogin()</code> / backend <code>start_oauth_login</code>), let app open default browser and start waiting for callback.</li></ol><p><strong>You should see</strong>:</p><ul><li>A copyable authorization link appears in dialog (event name: <code>oauth-url-generated</code>)</li><li>Browser opens Google authorization page; after authorization, it redirects to a local address and shows &quot;Authorization Successful!&quot; (<code>oauth_success_html()</code>)</li></ul><h3 id="step-3-when-oauth-doesn-t-complete-automatically-use-finish-oauth-to-manually-complete" tabindex="-1">Step 3: When OAuth Doesn&#39;t Complete Automatically, Use &quot;Finish OAuth&quot; to Manually Complete <a class="header-anchor" href="#step-3-when-oauth-doesn-t-complete-automatically-use-finish-oauth-to-manually-complete" aria-label="Permalink to &quot;Step 3: When OAuth Doesn&#39;t Complete Automatically, Use &quot;Finish OAuth&quot; to Manually Complete&quot;">​</a></h3><p><strong>Why</strong> OAuth flow has two stages: browser authorization gets <code>code</code>, then app uses <code>code</code> to exchange for token. Even if you didn&#39;t click &quot;Start OAuth&quot;, as long as you manually open authorization link and complete callback, dialog will try to automatically complete; if not successful, you can manually click once.</p><ol><li>If you &quot;copy link to open in your own browser&quot; (instead of default browser), after authorization callback returns, app will receive <code>oauth-callback-received</code> event and automatically call <code>completeOAuthLogin()</code> (see <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code>).</li><li>If you don&#39;t see automatic completion, click <strong>Finish OAuth</strong> in dialog (corresponds to backend <code>complete_oauth_login</code>).</li></ol><p><strong>You should see</strong>: Dialog shows success and automatically closes; new account appears in <code>Accounts</code> list.</p><div class="tip custom-block"><p class="custom-block-title">Pro tip: Copy link first when callback can&#39;t connect</p><p>Backend will try to listen on both IPv6 <code>::1</code> and IPv4 <code>127.0.0.1</code>, and choose <code>localhost/127.0.0.1/[::1]</code> as callback address based on listening status, mainly to avoid connection failures caused by &quot;browser resolving localhost to IPv6&quot;. (See <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>)</p></div><h3 id="step-4-add-manually-with-refresh-token-supports-bulk" tabindex="-1">Step 4: Add Manually with Refresh Token (Supports Bulk) <a class="header-anchor" href="#step-4-add-manually-with-refresh-token-supports-bulk" aria-label="Permalink to &quot;Step 4: Add Manually with Refresh Token (Supports Bulk)&quot;">​</a></h3><p><strong>Why</strong> When you can&#39;t get <code>refresh_token</code> (or you prefer &quot;portable asset&quot;), directly using Refresh Token is more controllable.</p><ol><li>Switch to <code>Refresh Token</code> tab.</li><li>Paste <code>refresh_token</code> into text box.</li></ol><p>Supported input formats (frontend will parse and batch add):</p><table tabindex="0"><thead><tr><th>Input Type</th><th>Example</th><th>Parsing Logic</th></tr></thead><tbody><tr><td>Pure token text</td><td><code>1//abc...</code></td><td>Regex extraction: <code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code> (see <code>AddAccountDialog.tsx:213-220</code>)</td></tr><tr><td>Embedded in text</td><td>Logs/exported text containing multiple <code>1//...</code></td><td>Regex batch extraction and deduplication (see <code>AddAccountDialog.tsx:213-224</code>)</td></tr><tr><td>JSON array</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>Parse array and take <code>item.refresh_token</code> (see <code>AddAccountDialog.tsx:198-207</code>)</td></tr></tbody></table><p>After clicking <strong>Confirm</strong>, dialog will call <code>onAdd(&quot;&quot;, token)</code> one by one according to token count (see <code>AddAccountDialog.tsx:231-248</code>), eventually landing in backend <code>add_account</code>.</p><p><strong>You should see</strong>:</p><ul><li>Dialog shows batch progress (e.g., <code>1/5</code>)</li><li>After success, new account appears in <code>Accounts</code> list</li></ul><h3 id="step-5-confirm-account-pool-is-available" tabindex="-1">Step 5: Confirm &quot;Account Pool is Available&quot; <a class="header-anchor" href="#step-5-confirm-account-pool-is-available" aria-label="Permalink to &quot;Step 5: Confirm &quot;Account Pool is Available&quot;&quot;">​</a></h3><p><strong>Why</strong> Successful addition doesn&#39;t equal &quot;immediately stable use&quot;. Backend will automatically trigger one &quot;refresh quota&quot; after addition, and try to reload token pool when Proxy is running, making changes take effect immediately.</p><p>You can confirm with these 2 signals:</p><ol><li>Account appears in list and shows email (email comes from backend <code>get_user_info</code>, not the email you input).</li><li>Account quota/subscription info starts refreshing (backend will automatically call <code>internal_refresh_account_quota</code>).</li></ol><p><strong>You should see</strong>: After adding, no need to manually click refresh; account will start showing quota info (success depends on actual interface display).</p><h2 id="checkpoints-✅" tabindex="-1">Checkpoints ✅ <a class="header-anchor" href="#checkpoints-✅" aria-label="Permalink to &quot;Checkpoints ✅&quot;">​</a></h2><ul><li>Can see new account&#39;s email in account list</li><li>Not stuck in &quot;loading&quot; state beyond acceptable time (OAuth callback should complete quickly after callback completes)</li><li>If you&#39;re running Proxy, new account can quickly participate in scheduling (backend will try to reload)</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="_1-oauth-shows-refresh-token-not-obtained" tabindex="-1">1) OAuth Shows &quot;Refresh Token Not Obtained&quot; <a class="header-anchor" href="#_1-oauth-shows-refresh-token-not-obtained" aria-label="Permalink to &quot;1) OAuth Shows &quot;Refresh Token Not Obtained&quot;&quot;">​</a></h3><p>Backend will explicitly check if <code>refresh_token</code> exists in <code>start_oauth_login/complete_oauth_login</code>; if not exists, will return error message with solution (see <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code>).</p><p>Handle according to source code prompts:</p><ol><li>Open <code>https://myaccount.google.com/permissions</code></li><li>Revoke <strong>Antigravity Tools</strong> access permission</li><li>Go back to app and redo OAuth</li></ol><blockquote><p>You can also directly switch to this lesson&#39;s Refresh Token channel.</p></blockquote><h3 id="_2-browser-shows-localhost-refused-to-connect" tabindex="-1">2) Browser Shows <code>localhost refused to connect</code> <a class="header-anchor" href="#_2-browser-shows-localhost-refused-to-connect" aria-label="Permalink to &quot;2) Browser Shows `localhost refused to connect`&quot;">​</a></h3><p>OAuth callback requires browser to request local callback address. To reduce failure rate, backend will:</p><ul><li>Try to listen on both <code>127.0.0.1</code> and <code>::1</code></li><li>Only use <code>localhost</code> when both are available, otherwise force use <code>127.0.0.1</code> or <code>[::1]</code></li></ul><p>Corresponding implementation in <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>.</p><h3 id="_3-switching-to-another-tab-cancels-oauth-preparation" tabindex="-1">3) Switching to Another Tab Cancels OAuth Preparation <a class="header-anchor" href="#_3-switching-to-another-tab-cancels-oauth-preparation" aria-label="Permalink to &quot;3) Switching to Another Tab Cancels OAuth Preparation&quot;">​</a></h3><p>When dialog switches from <code>OAuth</code> to other tab, frontend will call <code>cancelOAuthLogin()</code> and clear URL (see <code>AddAccountDialog.tsx:127-136</code>).</p><p>If you&#39;re in the middle of authorization, don&#39;t rush to switch tabs.</p><h3 id="_4-refresh-token-correct-incorrect-examples" tabindex="-1">4) Refresh Token Correct/Incorrect Examples <a class="header-anchor" href="#_4-refresh-token-correct-incorrect-examples" aria-label="Permalink to &quot;4) Refresh Token Correct/Incorrect Examples&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Example</th><th>Will be recognized</th><th>Reason</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td>Matches <code>1//</code> prefix rule (see <code>AddAccountDialog.tsx:215-219</code>)</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>Doesn&#39;t match frontend extraction rule, will be treated as invalid input</td></tr></tbody></table><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>OAuth: Suitable for &quot;fast&quot;, also supports copying link to your preferred browser and automatically/manually completing</li><li>Refresh Token: Suitable for &quot;stable&quot; and &quot;portable&quot;, supports batch extracting <code>1//...</code> from text/JSON</li><li>When you can&#39;t get <code>refresh_token</code>, revoke authorization according to error prompt and redo, or directly switch to Refresh Token channel</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><p>In the next lesson, we&#39;ll do something more practical: turn the account pool into a &quot;portable asset&quot;.</p><blockquote><p>Go learn <strong><a href="./../backup-migrate/">Account Backup &amp; Migration: Import/Export, V1/DB Hot Migration</a></strong>.</p></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Accounts page mounts add dialog</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>OAuth callback event triggers <code>completeOAuthLogin()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Refresh Token batch parsing and deduplication</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>Frontend calls Tauri commands (add/OAuth/cancel)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>Backend add_account: ignore email, use refresh_token to fetch real email and save</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>Backend OAuth: check refresh_token missing and provide revoke authorization solution</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>OAuth callback server: listen on IPv4/IPv6 simultaneously and choose redirect_uri</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Key Event Names</strong>:</p><ul><li><code>oauth-url-generated</code>: Backend sends OAuth URL to frontend after generation (see <code>oauth_server.rs:250-252</code>)</li><li><code>oauth-callback-received</code>: Backend notifies frontend after receiving callback and parsing code (see <code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code>)</li></ul><p><strong>Key Commands</strong>:</p><ul><li><code>prepare_oauth_url</code>: Pre-generate authorization link and start callback listening (see <code>src-tauri/src/commands/mod.rs:471-473</code>)</li><li><code>start_oauth_login</code>: Open default browser and wait for callback (see <code>src-tauri/src/commands/mod.rs:339-401</code>)</li><li><code>complete_oauth_login</code>: Don&#39;t open browser, just wait for callback and complete token exchange (see <code>src-tauri/src/commands/mod.rs:405-467</code>)</li><li><code>add_account</code>: Save account with refresh_token (see <code>src-tauri/src/commands/mod.rs:21-60</code>)</li></ul></details>',67)])])}const g=o(n,[["render",c]]);export{p as __pageData,g as default};
